#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle sensor timeout first - this forces safe idle */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Handle no input case - check for sensor timeout */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        controller_process_sensor_timeout(controller, input.now_ms);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Update sensor freshness based on valid input */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check for timeout after updating turbidity */
        if (controller->has_valid_level &&
            controller->last_level_ms != 0U &&
            (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
        }
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check for timeout after updating level */
        if (controller->has_valid_turbidity &&
            controller->last_turbidity_ms != 0U &&
            (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_idle(controller);
        }
    }

    /* Check if we should be in COMPLETE state (level < 15) */
    if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller->state = CONTROLLER_STATE_COMPLETE;
        controller->filter_on = false;
        controller->drain_open = false;
    }

    /* Now process control logic based on current state */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay in safe idle until both sensors are valid */
        if (!controller->has_valid_turbidity || !controller->has_valid_level) {
            break;
        }

        /* Check control policy */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            break;
        }

        /* TURB > 35 and LEVEL >= 40: start filtering */
        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Update clear streak based on turbidity */
        if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller->clear_streak_count++;
        } else {
            controller->clear_streak_count = 0;
        }

        /* Check for transition to SETTLING: clear streak >= 3, LEVEL >= 40 */
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = false;
            controller->drain_open = false;
            controller->settling_started_ms = input.now_ms;
            controller->state = CONTROLLER_STATE_SETTLING;
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check for disturbance: valid TURB > 40 returns to FILTERING */
        if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
        } else if (input.now_ms >= controller->settling_started_ms + CONTROLLER_SETTLING_MS &&
                   controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                   controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Ready to drain: 400ms settled, latest clear sample, level sufficient */
            controller->filter_on = false;
            controller->drain_open = true;
            controller->state = CONTROLLER_STATE_DRAINING;
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance: valid TURB > 50 and LEVEL >= 40 */
        if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->drain_open = false;
            controller->filter_on = true;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Stay in complete - filter off, drain closed */
        break;

    default:
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    return output;
}

